ChestManager = {}

ChestManager.chests = {}
setmetatable(ChestManager.chests, {__mode = "kv"}) --weak table

function ChestManager:createChest(pos, playerName)
    local ret, newPos = ToolUtil:getStandPos(pos)
    if ret == false then
        return nil
    end

    local chest = GameChest.new(newPos, playerName)
    ChestManager:addChest(chest)
    return chest
end

function ChestManager:onTick(ticks)
    local count = 0
    for _, chest in pairs(ChestManager.chests) do
        chest:onTick(ticks)
        count = count + 1
    end
    --HostApi.log("ChestManager.chests count: " .. count)
end

function ChestManager:syncChestInfo(rakssid)
    for _, chest in pairs(ChestManager.chests) do
        chest:syncChestInfo(rakssid, true)
    end
end

function ChestManager:addChest(chest)
    ChestManager.chests[VectorUtil.hashVector3(chest.pos)] = chest
end

function ChestManager:removeChest(chest)
    ChestManager.chests[VectorUtil.hashVector3(chest.pos)] = nil
end

return ChestManager